import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel for matmul + swish + scaling with tiling
fused_matmul_swish_scale_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <c10/cuda/CUDAStream.h>

template<typename T>
__device__ __forceinline__ T swish_fast(T x) {
    // Fast approximate sigmoid: 0.5 * tanh(0.5 * x) + 0.5
    T half_x = x * T(0.5);
    T tanh_val = tanhf(half_x);
    T sigmoid = tanh_val * T(0.5) + T(0.5);
    return x * sigmoid;
}

template<typename T, int TILE_SIZE>
__global__ void fused_matmul_swish_scale_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    float scaling_factor,
    int batch_size,
    int in_features,
    int out_features) {

    // Shared memory for tile of input and weight matrices
    __shared__ T input_tile[TILE_SIZE][TILE_SIZE];
    __shared__ T weight_tile[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    T thread_sum = T(0);

    // Loop over tiles
    for (int tile = 0; tile < (in_features + TILE_SIZE - 1) / TILE_SIZE; ++tile) {
        int input_col = tile * TILE_SIZE + threadIdx.x;
        int weight_row = tile * TILE_SIZE + threadIdx.y;

        // Load input tile
        if (row < batch_size && input_col < in_features) {
            input_tile[threadIdx.y][threadIdx.x] = input[row * in_features + input_col];
        } else {
            input_tile[threadIdx.y][threadIdx.x] = T(0);
        }

        // Load weight tile (transposed for better memory access)
        if (col < out_features && weight_row < in_features) {
            weight_tile[threadIdx.y][threadIdx.x] = weight[col * in_features + weight_row];
        } else {
            weight_tile[threadIdx.y][threadIdx.x] = T(0);
        }

        __syncthreads();

        // Compute partial sum for this tile
        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            thread_sum += input_tile[threadIdx.y][k] * weight_tile[k][threadIdx.x];
        }

        __syncthreads();
    }

    // Write result with activation and scaling
    if (row < batch_size && col < out_features) {
        if (bias != nullptr) {
            thread_sum += bias[col];
        }

        T activated = swish_fast(thread_sum);
        output[row * out_features + col] = activated * T(scaling_factor);
    }
}

torch::Tensor fused_matmul_swish_scale_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float scaling_factor) {

    auto batch_size = input.size(0);
    auto in_features = input.size(1);
    auto out_features = weight.size(0);

    auto output = torch::empty({batch_size, out_features},
                              input.options().device(torch::kCUDA));

    const int TILE_SIZE = 32;
    dim3 block_size(TILE_SIZE, TILE_SIZE);
    dim3 grid_size(
        (out_features + TILE_SIZE - 1) / TILE_SIZE,
        (batch_size + TILE_SIZE - 1) / TILE_SIZE
    );

    cudaStream_t stream = c10::cuda::getCurrentCUDAStream();

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_matmul_swish_scale_cuda", ([&] {
        fused_matmul_swish_scale_kernel<scalar_t, TILE_SIZE><<<grid_size, block_size, 0, stream>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            output.data_ptr<scalar_t>(),
            scaling_factor,
            batch_size,
            in_features,
            out_features
        );
    }));

    return output;
}
"""

fused_matmul_swish_scale_cpp_source = """
torch::Tensor fused_matmul_swish_scale_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float scaling_factor);
"""

# Compile the inline CUDA code
fused_matmul_swish_scale = load_inline(
    name="fused_matmul_swish_scale",
    cpp_sources=fused_matmul_swish_scale_cpp_source,
    cuda_sources=fused_matmul_swish_scale_source,
    functions=["fused_matmul_swish_scale_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model with fused matmul + swish + scaling CUDA kernel using tiling.
    """
    def __init__(self, in_features, out_features, scaling_factor):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.scaling_factor = scaling_factor

        # Initialize weights and bias
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        self.bias = nn.Parameter(torch.empty(out_features))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

        self.fused_kernel = fused_matmul_swish_scale

    def forward(self, x):
        return self.fused_kernel.fused_matmul_swish_scale_cuda(
            x, self.weight, self.bias, self.scaling_factor
        )

